#!/usr/bin/env python3
import os, base64

files = {
    'tailwind.config.ts': '',
    'app/globals.css': '',
    'app/layout.tsx': '',
    'app/page.tsx': '',
    'components/SkillableLogo.tsx': '',
    'components/Nav.tsx': '',
    'components/Hero.tsx': '',
    'components/LogoStrip.tsx': '',
    'components/Features.tsx': '',
    'components/HowItWorks.tsx': '',
    'components/Pricing.tsx': '',
    'components/Testimonials.tsx': '',
    'components/FAQ.tsx': '',
    'components/CtaBanner.tsx': '',
    'components/Footer.tsx': '',
}

for path, b64 in files.items():
    d = os.path.dirname(path)
    if d: os.makedirs(d, exist_ok=True)
    open(path, 'w').write(base64.b64decode(b64).decode('utf-8'))
    print('OK:', path)
print('\nTodos los archivos creados!')